import React, { useState } from "react";

export default function Contact() {
  const [formData, setFormData] = useState({
    nombre: "",
    edad: "",
    condicion: "",
    email: "",
    celular: "",
    mensaje: "",
  });

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    alert(
      "Solicitud enviada correctamente. Nos pondremos en contacto a la brevedad.",
    );

    setFormData({
      nombre: "",
      edad: "",
      condicion: "",
      email: "",
      celular: "",
      mensaje: "",
    });
  };

  return (
    <div style={styles.page}>
      <div style={styles.container}>
        <div style={styles.card}>
          <h1 style={styles.title}>Atención personalizada</h1>

          <p style={styles.subtitle}>
            Si desea solicitar nuestros servicios o realizar una consulta
            particular, complete el siguiente formulario. Nos pondremos en
            contacto con usted a la brevedad.
          </p>

          <form onSubmit={handleSubmit} style={styles.form}>
            <div style={styles.group}>
              <label>Nombre completo</label>
              <input
                type="text"
                name="nombre"
                value={formData.nombre}
                onChange={handleChange}
                required
                style={styles.input}
              />
            </div>

            <div style={styles.group}>
              <label>Edad</label>
              <input
                type="number"
                name="edad"
                value={formData.edad}
                onChange={handleChange}
                required
                style={styles.input}
              />
            </div>

            <div style={styles.group}>
              <label>Condición</label>

              <select
                name="condicion"
                value={formData.condicion}
                onChange={handleChange}
                required
                style={styles.input}
              >
                <option value="">Seleccione una opción</option>

                <option>Jubilado o pensionista</option>

                <option>Estudiante universitario</option>

                <option>Estudiante de educación media</option>

                <option>Niño en edad escolar</option>

                <option>Persona con discapacidad</option>

                <option>Otro</option>
              </select>
            </div>

            <div style={styles.group}>
              <label>Correo electrónico</label>

              <input
                type="email"
                name="email"
                value={formData.email}
                onChange={handleChange}
                required
                style={styles.input}
              />
            </div>

            <div style={styles.group}>
              <label>Celular</label>

              <input
                type="text"
                name="celular"
                value={formData.celular}
                onChange={handleChange}
                required
                style={styles.input}
              />
            </div>

            <div style={styles.group}>
              <label>Mensaje</label>

              <textarea
                name="mensaje"
                value={formData.mensaje}
                onChange={handleChange}
                rows="6"
                required
                style={styles.textarea}
                placeholder="Describa su situación o consulta..."
              />
            </div>

            <button type="submit" style={styles.button}>
              Enviar solicitud
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    backgroundColor: "#f0f9ff",
    padding: "3rem 1rem",
  },

  container: {
    maxWidth: "800px",
    margin: "0 auto",
  },

  card: {
    backgroundColor: "white",
    padding: "2.5rem",
    borderRadius: "20px",
    boxShadow: "0 4px 16px rgba(0,0,0,.08)",
  },

  title: {
    color: "#32d5d5",
    textAlign: "center",
    marginBottom: "1rem",
    fontSize: "2rem",
  },

  subtitle: {
    color: "#64748b",
    textAlign: "center",
    marginBottom: "2rem",
    lineHeight: "1.8",
  },

  form: {
    display: "flex",
    flexDirection: "column",
    gap: "1.3rem",
  },

  group: {
    display: "flex",
    flexDirection: "column",
    gap: ".5rem",
    color: "#475569",
    fontWeight: "600",
  },

  input: {
    padding: ".9rem",
    borderRadius: "10px",
    border: "1px solid #cbd5e1",
    fontSize: ".95rem",
    outline: "none",
  },

  textarea: {
    padding: "1rem",
    borderRadius: "10px",
    border: "1px solid #cbd5e1",
    resize: "vertical",
    fontSize: ".95rem",
    outline: "none",
  },

  button: {
    marginTop: "1rem",
    padding: "1rem",
    border: "none",
    borderRadius: "12px",
    backgroundColor: "#32d5d5",
    color: "white",
    fontWeight: "700",
    fontSize: "1rem",
    cursor: "pointer",
  },
};
